function getVideoStats(videoId, apiKey) {
 const cache = CacheService.getScriptCache();
 const cachedData = cache.get(`videoStats-${videoId}`);
 if (cachedData) {
 return JSON.parse(cachedData);
 }

 const url = `https://www.googleapis.com/youtube/v3/videos?part=statistics,contentDetails&id=${videoId}&key=${apiKey}`;
 const response = UrlFetchApp.fetch(url);
 const json = JSON.parse(response.getContentText());
 console.log(`json: ${json}`);
 const viewCount = json.items[0].statistics.viewCount;
 const likeCount = json.items[0].statistics.likeCount;
 const dislikeCount = json.items[0].statistics.dislikeCount;
 const favoriteCount = json.items[0].statistics.favoriteCount;
 const commentCount = json.items[0].statistics.commentCount;
 const durationISO = json.items[0].contentDetails.duration;
 console.log(`durationISO: ${durationISO}`);

 let duration = "0:00:00";
 if (durationISO) {
 const durationMatch = durationISO.match(iso8601DurationRegex);
 if (durationMatch) {
 const hours = durationMatch[1] || "0";
 const minutes = durationMatch[2] || "0";
 const seconds = durationMatch[3] || "0";
 duration = `${hours}:${minutes.padStart(2, "0")}:${seconds.padStart(2, "0")}`;
 }
 }

 const videoStats = { viewCount, likeCount, dislikeCount, favoriteCount, commentCount, duration};

 console.log(`viewCount: ${viewCount}`);
 console.log(`duration: ${duration}`);


 const cacheExpirationInSeconds = 60 \* 60; // Cache expiration time in seconds
 cache.put(`videoStats-${videoId}`, JSON.stringify(videoStats), cacheExpirationInSeconds);

 return videoStats;
}
function getChannelStats(channelId, apiKey) {
 const cache = CacheService.getScriptCache();
 const cachedData = cache.get(`channelStats-${channelId}`);
