\title{Improvements and Challenges in StarCraft II Macro-Management: A Study on the MSC Dataset}

\author{
Huikai Wu\thanks{NLPR, Institute of Automation, Chinese Academy of Sciences, huikai.wu@nlpr.ia.ac.cn} 
