/\*\*
 \* Transforms raw data from the Facebook API into an array of video metrics and calculated values
 \* @param {Object} rawData - The raw data object to transform
 \* @returns {Array} An array of video metrics and calculated values to be used for loading
 \*/
function transformRawData(rawData) {
 // 1. Prepare and format data Fields
 const attachmentData = rawData.attachments?.data?.[0] || {};
 const URL\_Facebook = rawData.permalink\_url;
 const URL\_Target = attachmentData.url;
 const Fecha = new Date(rawData.created\_time);
 const YY\_MM = Fecha.getFullYear().toString().slice(2) + "-" + (Fecha.getMonth() + 1).toString().padStart(2, '0');
 const Titulo = attachmentData.title;
 const Copy = rawData.message;
 const Id = rawData.id.split('\_')[1];

 // 2. Process insights metrics
 const insightsDataMap = new Map(
 rawData.insights?.data?.map((insight) => [insight.name, insight]) || []
 );
 const insightsData = Object.entries(INSIGHT\_METRICS\_MAP).reduce(function (acc, [metric, value]) {
 // Find the corresponding insight object using the insightsDataMap
 const insight = insightsDataMap.get(metric);
 // Get the value of the metric from the insight object or use 0 if it's not available
 const metricValue = insight?.values?.[0]?.value || 0;

 if (metric === "post\_activity\_by\_action\_type") {
 // Iterate through the entries of the value object (submetrics)
 for (const [action, label] of Object.entries(value)) {
 // Add the value of the submetric to the accumulator object using its label
 acc[label] = metricValue[action] || 0;
 }
 } else if (typeof value === "object") {
 // If the value is an object (submetrics), iterate through its entries
 for (const [action, label] of Object.entries(value)) {
 // Add the value of the submetric to the accumulator object using its label
 acc[label] = metricValue[action] || 0;
 }
 } else {
 // For other metrics, add their values to the accumulator object using the value as the key
 acc[value] = metricValue;
 }

 // Return the accumulator object to be used in the next iteration or as the final result
 return acc;
 }, {}); // Initialize the accumulator object as an empty object
 // 3. Extract individual metric values from the insights object
 const {
 Reach,
 Other\_clicks,
 Link\_Clicks,
 Photo\_View,
 Likes,
 Comments,
 Share
 } = insightsData;

 // 4. Perform calculations using data and insights to generate custom metrics
 const CTR = (Link\_Clicks / Reach) || 0;

 // Determine the type of rawData (photo or share) based on the attachment type
 const type = rawData.attachments?.data?.[0]?.type;

 // 5. Build an array with the fields and metrics extracted and calculated metrics
 let Data\_Load\_Object;
 if (type === 'photo') {
 Data\_Load\_Object = [
 Fecha,
 URL\_Facebook,
 Copy,
 Reach,
 Other\_clicks,
 Photo\_View,
 Likes,
 Comments,
 Share,
 Id,
 YY\_MM
 ];
 } else if (type === 'share') {
 Data\_Load\_Object = [
 Fecha,
 URL\_Facebook,
 URL\_Target,
 Titulo,
 Copy,
 Reach,
 CTR,
 Link\_Clicks,
 Other\_clicks,
 Likes,
 Comments,
 Share,
 Id,
 YY\_MM
 ];
 }

 return {
 type,
 data: Data\_Load\_Object
 };
}


