function appendData(configByType, configColumns, transformedData) {
 // 1) Open the spreadsheet and select the sheet
 const sheet = SpreadsheetApp.openById(configByType.SPREADSHEET\_ID).getSheetByName(configByType.SHEET\_NAME);

 // 2) Calculate the number of columns and rows of the object
 const numRows = transformedData.length;
 const numColumns = transformedData[0].length;

 // 3) Find the first empty row after the existing data
 const lastRow = sheet.getLastRow();
 const startingRow = lastRow + 1;

 // 4) Set the values in the new data range
 sheet.getRange(startingRow, 1, numRows, numColumns).setValues(transformedData);
}


function deleteAndLoadData(configByType, transformedData) {
 // 1) Open the spreadsheet and select the sheet
 const sheet = SpreadsheetApp.openById(configByType.SPREADSHEET\_ID).getSheetByName(configByType.SHEET\_NAME);

 if (transformedData.length === 0) {
 console.log('No data to load');
 return;
 }

 // 2) Calculate the number of columns and rows of the object
 const numRows = transformedData.length;
 const numColumns = transformedData[0].length;

 // 3) Clear the content in the existing data range
 const startingCell = sheet.getRange(configByType.LOAD\_STARTING\_CELL);
 const startingRow = startingCell.getRow();
 const startingColumn = startingCell.getColumn();
 const lastRow = sheet.getLastRow();

 if (lastRow > startingRow) {
 sheet.getRange(startingRow, startingColumn, lastRow - startingRow + 1, numColumns).clearContent();
 }

 // 4) Set the values in the new data range
 sheet.getRange(startingRow, startingColumn, numRows, numColumns).setValues(transformedData);
}

