 if (board[i][j] == EMPTY)
 {
 return false;
 }
 }
 }
 return true;
}

void DrawBoard(bool gameOver, int winner)
{
 for (int i = 1; i < BOARD\_SIZE; i++)
 {
 DrawLine(i \* CELL\_SIZE, 0, i \* CELL\_SIZE, SCREEN\_HEIGHT, BLACK);
 DrawLine(0, i \* CELL\_SIZE, SCREEN\_WIDTH, i \* CELL\_SIZE, BLACK);
 }

 for (int i = 0; i < BOARD\_SIZE; i++)
 {
 for (int j = 0; j < BOARD\_SIZE; j++)
 {
 int x = j \* CELL\_SIZE;
 int y = i \* CELL\_SIZE;

 if (board[i][j] == PLAYER1)
 {
 DrawText("X", x + CELL\_SIZE / 2 - 10, y + CELL\_SIZE / 2 - 10, 20, BLACK);
 }
 else if (board[i][j] == PLAYER2)
 {
 DrawText("O", x + CELL\_SIZE / 2 - 10, y + CELL\_SIZE / 2 - 10, 20, BLACK);
 }
 }
 }

 if (gameOver && winner)
 {
 int dir = GetWinningDirection(winner);
 if (dir >= 1 && dir <= BOARD\_SIZE)
 { // Horizontal line
 int y = (dir - 1) \* CELL\_SIZE + CELL\_SIZE / 2;
 DrawLine(0, y, SCREEN\_WIDTH, y, RED);
 }
 else if (dir >= BOARD\_SIZE + 1 && dir <= 2 \* BOARD\_SIZE)
 { // Vertical line
 int x = (dir - BOARD\_SIZE - 1) \* CELL\_SIZE + CELL\_SIZE / 2;
 DrawLine(x, 0, x, SCREEN\_HEIGHT, RED);
 }
 else if (dir == 2 \* BOARD\_SIZE + 1)
 { // Diagonal from top-left to bottom-right
 DrawLine(0, 0, SCREEN\_WIDTH, SCREEN\_HEIGHT, RED);
 }
 else if (dir == 2 \* BOARD\_SIZE + 2)
 { // Diagonal from top-right to bottom-left
 DrawLine(SCREEN\_WIDTH, 0, 0, SCREEN\_HEIGHT, RED);
 }
 }
}

void DrawWinMessage(int winner)
{
 const char \*messageLine1;
