using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Xml.Schema;

internal class XmlSchemaFilter
{
 public XmlSchemaSet FilterSchema(XmlSchemaSet schemaSet, string[] filteredElements)
 {
 var filteredSchemaSet = new XmlSchemaSet();
 var originalSchema = schemaSet.Schemas().Cast().First();
 var filteredSchema = new XmlSchema
 {
 AttributeFormDefault = originalSchema.AttributeFormDefault,
 ElementFormDefault = originalSchema.ElementFormDefault,
 TargetNamespace = originalSchema.TargetNamespace
 };

 foreach (var item in originalSchema.Items)
 {
 if (item is XmlSchemaElement element && filteredElements.Contains(element.QualifiedName.Name))
 {
 filteredSchema.Items.Add(element);
 }
 else if (item is XmlSchemaComplexType complexType && filteredElements.Any(name => complexType.QualifiedName.Name.StartsWith(name)))
 {
 filteredSchema.Items.Add(complexType);
 }
 }

 filteredSchemaSet.Add(filteredSchema);
 filteredSchemaSet.Compile();
 return filteredSchemaSet;
 }

#pragma warning disable S3776
 private void EnumerateDeep(XmlSchemaType type, XmlSchema schema, HashSet visitedTypes, XmlSchema outputSchema)
#pragma warning restore S3776
 {
 if (type == null || visitedTypes.Contains(type.Name))
 {
 return;
 }

 visitedTypes.Add(type.Name);

 if (type is XmlSchemaComplexType complexType)
 {
 foreach (var attribute in complexType.AttributeUses.Values.OfType())
 {
 this.EnumerateDeep(attribute.AttributeSchemaType, schema, visitedTypes, outputSchema);
 }

 if (complexType.ContentTypeParticle is XmlSchemaGroupBase groupBase)
 {
 foreach (var particle in groupBase.Items.OfType())
 {
 if (particle is XmlSchemaElement element)
 {
 this.EnumerateDeep(element.ElementSchemaType, schema, visitedTypes, outputSchema);
 }
 else if (particle is XmlSchemaGroupRef groupRef)
 {
#pragma warning disable S1905
 this.EnumerateDeep(groupRef.Particle, schema, visitedTypes, outputSchema);
#pragma warning restore S1905
 }
 }
 }
 }
 }

 private void EnumerateDeep(XmlSchemaGroupBase? groupBase, XmlSchema schema, HashSet visitedTypes, XmlSchema outputSchema)
 {
 if (groupBase == null)
 {
 return;
 }

 foreach (var particle in groupBase.Items)
 {
 if (particle is XmlSchemaElement element)
 {
 this.EnumerateDeep(element.ElementSchemaType, schema, visitedTypes, outputSchema);
 }
 else if (particle is XmlSchemaGroupBase nestedGroup)
 {
 this.EnumerateDeep(nestedGroup, schema, visitedTypes, outputSchema);
 }
 }
 }
