using Xunit;
using Xunit.Abstractions;

public class XmlSchemaFilterTests
{
 private readonly ITestOutputHelper testOutputHelper;
 private readonly XmlSchemaFilter sut;

 public XmlSchemaFilterTests(ITestOutputHelper testOutputHelper)
 {
 this.testOutputHelper = testOutputHelper;
 this.sut = new XmlSchemaFilter();
 }

 [Fact]
 public void FilterSchema\_Works()
 {
 // Arrange
 var schemaSet = this.GetSchemaSet();

 var contractTypes = new List
 {
 new(
 "PingRq\_MType",
 "JackHenry.JHAContractTypes.Ping",
 Provider.SilverLake)
 };

 // Act
 var result = this.sut.FilterSchema(schemaSet, contractTypes);

 this.testOutputHelper.WriteLine("Filtered schema items count: " + result.Schemas().Cast().First().Items.Count);

 foreach (var item in result.Schemas().Cast().First().Items)
 {
 if (item is XmlSchemaElement element)
 {
 this.testOutputHelper.WriteLine("Element: " + element.QualifiedName);
 }
 else if (item is XmlSchemaComplexType complexType)
 {
 this.testOutputHelper.WriteLine("ComplexType: " + complexType.QualifiedName);
 }
 }

 // Assert
 Assert.Single(result.Schemas());

 var schema = result.Schemas().Cast().Single();

 Assert.Collection(
 schema.Items.Cast(),
 item =>
 {
 Assert.IsType(item);
 var element = (XmlSchemaElement)item;
 Assert.Equal("Ping", element.Name);
 Assert.Equal("PingRq\_MType", element.ElementSchemaType!.Name);
 },
 item =>
 {
 Assert.IsType(item);
 var complexType = (XmlSchemaComplexType)item;
 Assert.Equal("PingRq\_MType", complexType.Name);
 },
 item =>
 {
 Assert.IsType(item);
 var complexType = (XmlSchemaComplexType)item;
 Assert.Equal("PingRq\_Type", complexType.Name);
 },
 item =>
 {
 Assert.IsType(item);
 var complexType = (XmlSchemaComplexType)item;
 Assert.Equal("Ver\_1\_CType", complexType.Name);
 });
 }

 private XmlSchemaSet GetSchemaSet()
 {
 var set = new XmlSchemaSet
 {
 XmlResolver = new XmlUrlResolver()
 };

 var settings = new XmlReaderSettings { DtdProcessing = DtdProcessing.Ignore };

 var reader = XmlReader.Create(
 Path.GetFullPath("SampleXsd/PingContracts.xsd"), settings);

 set.Add(null, reader);

 return set;
 }
}
